def _batch_stats(self, x):
        mu = torch.mean(x, dim=0, keepdim=True)
        var = torch.var(x, dim=0, keepdim=True)
        return mu, var

def __str__(self):
        return '\n'.join([self.header, self.sequence, self.header2, 
                array('b', [x + self.qbase for x in self.quality]).tostring()])

def get_step_handler_for_gym_env(gym_env_name: str, cfg: Configuration) -> StepRewardDoneHandler:

    if gym_env_name == 'Acrobot-v1':
        handler = AcrobotStepHandler(cfg)
    elif gym_env_name == 'CartPole-v1':
        handler = CartPoleStepHandler(cfg)
    elif gym_env_name == 'MountainCarContinuous-v0':
        handler = ContinuousMountainCarStepHandler(cfg)
    elif gym_env_name == 'MountainCar-v0':
        handler = MountainCarStepHandler(cfg)
    elif gym_env_name == 'Pendulum-v0':
        handler = PendulumStepHandler(cfg)
    else:
        raise NotImplementedError(f'No support for this gym env: {gym_env_name}')

    return handler

def create_spiders_list():
    spiders_lst = [obj for obj in globals().values() if
                   inspect.isclass(obj) and str(obj).split('.')[2] == 'spiders' and 'BaseSpider' not in str(obj)]
    visible_projects = find_visible_projects()
    spiders_dict = {i.split('.')[0]: [obj for obj in spiders_lst if i.split('.')[0] in str(obj)] for i in
                    os.listdir('HousingPriceScraper/HousingPriceScraper/spiders/SpiderGroups')[:-1] if i.split('.')[0] in visible_projects}
    if len(list(spiders_dict.keys())) > 0:
        spiders_lst = select_spiders(spiders_dict)
    else:
        print('There are no visible projects, got to set_visible_projects to set defaults')
        return False
    return spiders_lst

def game(self, game_id=None, secret=None):
        if game_id is not None:
            self.game_id = game_id

        if secret is not None:
            self.secret = secret

        return self.game_id, self.secret

